import{_ as a,c as e,a as i,o as n}from"./app-CEcM0piI.js";const t={};function d(l,s){return n(),e("div",null,s[0]||(s[0]=[i(`<h2 id="属性选择器" tabindex="-1"><a class="header-anchor" href="#属性选择器"><span>属性选择器</span></a></h2><table><thead><tr><th>选择符</th><th>简介</th></tr></thead><tbody><tr><td>E[att]</td><td>选择具有att属性的E元素</td></tr><tr><td>E[att=&quot;val&quot;]</td><td>选择具有att属性且属性值等于val的E元素</td></tr><tr><td>E[att^=&quot;val&quot;]</td><td>匹配具有att属性且值以val开头的E元素</td></tr><tr><td>E[att$=&quot;val&quot;]</td><td>匹配具有att属性且值以val结尾的E元素</td></tr><tr><td>E[att*=&quot;val&quot;]</td><td>匹配具有att属性目值中含有val的E元素</td></tr></tbody></table><h2 id="结构伪类选择器" tabindex="-1"><a class="header-anchor" href="#结构伪类选择器"><span>结构伪类选择器</span></a></h2><p>结构伪类选择器主要根据文档结构来选择器元素，常用于根据父级选择器里面的子元素 根据结构选择</p><table><thead><tr><th>选择符</th><th>简介</th></tr></thead><tbody><tr><td>E:first-child</td><td>匹配父元素中的第一个子元素E</td></tr><tr><td>E:last-child</td><td>匹配父元素中最后一个E元素</td></tr><tr><td>E:nth-child(n)</td><td>匹配父元素中的第n个子元素E</td></tr><tr><td>E:first-of-type</td><td>指定类型E的第一个</td></tr><tr><td>E:last-of-type</td><td>指定类型E的最后一个</td></tr><tr><td>E:nth-of-type(n)</td><td>指定类型E的第n个</td></tr></tbody></table><p>n可以是数字，关键字和公式 n如果是数字，就是选择第n个子元素,元素的索引从1开始 n可以是关键字：even偶数，odd奇数</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>ul 1i:nth-child(2){</span></span>
<span class="line"><span>	background-color:skyblue;</span></span>
<span class="line"><span>}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>n是公式:常见的公式如下（如果n是公式，则从0开始计算，但是第0个元素或者超出了元素的个数会被忽略）</p><table><thead><tr><th>公式</th><th>取值</th></tr></thead><tbody><tr><td>2n</td><td>偶数</td></tr><tr><td>2n+1</td><td>奇数</td></tr><tr><td>5n</td><td>5,10,15......</td></tr><tr><td>n+5</td><td>从第5个开始（包含第五个）到最后</td></tr><tr><td>-n+5</td><td>前5个（包含第5个）</td></tr></tbody></table><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>        section div:nth-child(1) {</span></span>
<span class="line"><span>            background-color: red;</span></span>
<span class="line"><span>        }</span></span>
<span class="line"><span>        </span></span>
<span class="line"><span>        section div:nth-of-type(1) {</span></span>
<span class="line"><span>            background-color: blue;</span></span>
<span class="line"><span>        }</span></span>
<span class="line"><span></span></span>
<span class="line"><span>    &lt;section&gt;</span></span>
<span class="line"><span>        &lt;p&gt;光头强&lt;/p&gt;</span></span>
<span class="line"><span>        &lt;div&gt;熊大&lt;/div&gt;//blue</span></span>
<span class="line"><span>        &lt;div&gt;熊二&lt;/div&gt;</span></span>
<span class="line"><span>    &lt;/section&gt;</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>type和child的不同</p><p>nth-of-type会把指定元素的盒子排列序号 执行的时候首先看：nth-chiLd(1)之后回去看前面div</p><p>nth-child会把所有的盒子都排列序号 执行的时候直接看:nth-child(1)</p><h2 id="伪元素选择器" tabindex="-1"><a class="header-anchor" href="#伪元素选择器"><span>伪元素选择器</span></a></h2><p>伪元素选择器可以帮助我们利用CSS创建新标签元素，而不需要HTML标签，从而简化HTML结构。</p><table><thead><tr><th>选择符</th><th>简介</th></tr></thead><tbody><tr><td>::before</td><td>在元素内部的前面插入内容</td></tr><tr><td>::after</td><td>在元素内部的后面插入内容<br></td></tr></tbody></table><ul><li>before和after创建一个元素，但是属于行内元素</li><li>新创建的这个元素在文档树中是找不到的，所以称为伪元素</li><li>before和after必须有content属性</li><li>before在父元素内容的前面创建元素，after在父元素内容的后面插入元素</li><li>伪元素选择器和标签选择器一样，权重为1</li></ul><p><strong>黑色遮罩层</strong> 若想要实现黑色遮罩层可以先做一个与原盒子相同大小的盒子设置其背景颜色和透明度,先设置为不显示,然后设置鼠标经过时间</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>.tudou:hover .mask{</span></span>
<span class="line"><span>	display:block;</span></span>
<span class="line"><span>}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>这样的写法是当鼠标经过的时候设置mask属性可见</p><p>CSS3之后可以使用伪元素选择器创建遮罩</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>        .tudou::before {</span></span>
<span class="line"><span>            content: &#39;&#39;;</span></span>
<span class="line"><span>            display: none;</span></span>
<span class="line"><span>            position: absolute;</span></span>
<span class="line"><span>            top: 0;</span></span>
<span class="line"><span>            left: 0;</span></span>
<span class="line"><span>            width: 100%;</span></span>
<span class="line"><span>            height: 100%;</span></span>
<span class="line"><span>            background: rgba(0, 0, 0, .4) url(images/user.jpg) no-repeat center;</span></span>
<span class="line"><span>        }</span></span>
<span class="line"><span></span></span>
<span class="line"><span>        .tudou:hover::before{</span></span>
<span class="line"><span>            display: block;</span></span>
<span class="line"><span>        }</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>这样写法是当鼠标经过时调用该伪元素选择器</p><p><strong>伪元素选择器清除浮动</strong> 后面两种伪元素清除浮动算是第一种额外标签法的一个升级和优化</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>.clearfix:before,.clearfix:after{</span></span>
<span class="line"><span>	content:&quot;&quot;;</span></span>
<span class="line"><span>	display:table;</span></span>
<span class="line"><span>}</span></span>
<span class="line"><span>.clearfix:after{</span></span>
<span class="line"><span>	clear:both;</span></span>
<span class="line"><span>}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h1 id="盒子模型" tabindex="-1"><a class="header-anchor" href="#盒子模型"><span>盒子模型</span></a></h1><p>CSS3中可以通过box-sizing来指定盒模型，有2个值：即可指定为content-box、border-box，这样我们计算盒子大小的方式就发生了改变。</p><p>传统模式宽度计算：盒子的宽度=CSS中设置的width+border+padding CSS3盒子模型：盒子的宽度=CSS中设置的宽度width里面包含了border和padding</p><p>原本的盒子模型在更改border和padding值时盒子也会跟着变大,若想要盒子保持原尺寸只能再减去border和padding的值 css3新增的盒子模型的border和padding不会向外扩大,而是向内扩大</p><ol><li>box-sizing:content-box盒子大小为width+padding+border（以前默认的）</li><li>box-sizing:border-box盒子大小为width 如果盒子模型我们改为了box-sizing:border-box，那padding和border就不会撑大盒子了（前提padding和border不会超过width宽度）</li></ol><h1 id="滤镜filter" tabindex="-1"><a class="header-anchor" href="#滤镜filter"><span>滤镜filter</span></a></h1><p>filter CSS属性将模糊或颜色偏移等图形效果应用于元素</p><p>语法</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>filter:函数();</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>例如： blur模糊处理,数值越大越模糊</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>filter:blur(5px);</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><h1 id="计算" tabindex="-1"><a class="header-anchor" href="#计算"><span>计算</span></a></h1><p>calc函数可以让属性进行一些数值计算 如:让子盒子宽度永远比父盒子小30像素</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>.son{</span></span>
<span class="line"><span>	width:calc(100%-30px);</span></span>
<span class="line"><span>}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h1 id="过渡" tabindex="-1"><a class="header-anchor" href="#过渡"><span>过渡</span></a></h1><p>过渡（transition)是CSS3中具有颠覆性的特征之一，我们可以在不使用Flash动画或JavaScript的情况下，当元素从一种样式变换为另一种样式时为元素添加效果。</p><p>过渡动画：是从一个状态渐渐的过渡到另外一个状态 切换状态时会调用</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>transition: 要过渡的属性 花费时间 运动曲线 开始时间;</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><ol><li>属性：想要变化的css 属性，宽度高度 背景颜色 内外边距都可以。如果想要所有的属性都变化过渡，写一个all就可以。</li><li>花费时间：单位是秒（必须写单位）比如0.5s</li><li>运动曲线：默认是ease（可以省略）</li><li>何时开始：单位是秒（必须写单位）可以设置延迟触发时间默认是0s（可以省略）</li></ol><p>示例: 要想更改的属性都有过度效果需要使用逗号隔开 让所有属性变化都有过度效果写all即可</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>        div {</span></span>
<span class="line"><span>            width: 200px;</span></span>
<span class="line"><span>            height: 100px;</span></span>
<span class="line"><span>            background-color: pink;</span></span>
<span class="line"><span>            transition: width .5s,height .5s;</span></span>
<span class="line"><span>	        /* transition: all .5s; */</span></span>
<span class="line"><span>        }</span></span>
<span class="line"><span></span></span>
<span class="line"><span>        div:hover {</span></span>
<span class="line"><span>            width: 400px;</span></span>
<span class="line"><span>            height:200px;</span></span>
<span class="line"><span>        }</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h1 id="_2d转换" tabindex="-1"><a class="header-anchor" href="#_2d转换"><span>2D转换</span></a></h1><h2 id="移动" tabindex="-1"><a class="header-anchor" href="#移动"><span>移动</span></a></h2><p>根据给定的x,y坐标移动</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>transform: translate(x,y)</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>若某个坐标不需要移动给参数0即可 也可以单独移动一个坐标:<code>translateX</code>和<code>translateY</code></p><p>translate最大的优点：</p><ol><li>不会影响到其他元素的位置</li><li>translate中的百分比单位是相对于自身元素的translate:(50%,50%);</li><li><mark>对行内标签没有效果</mark></li></ol><h2 id="旋转" tabindex="-1"><a class="header-anchor" href="#旋转"><span>旋转</span></a></h2><p>rotate里面跟度数，单位是deg比如rotate(45deg) 角度为正时，顺时针，负时，为逆时针 默认旋转的中心点是元素的中心点</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>transform:rotate(度数)</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><h2 id="转换中心点" tabindex="-1"><a class="header-anchor" href="#转换中心点"><span>转换中心点</span></a></h2><p>设置元素转换的中心点</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>transform-origin:X Y;</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>后面的参数×和y用空格隔开x y 默认转换的中心点是元素的中心点 (50%50%) 还可以给xy设置像素或者方位名词J(top bottom left right center)</p><h2 id="缩放" tabindex="-1"><a class="header-anchor" href="#缩放"><span>缩放</span></a></h2><p>transform:scale(2,2）：宽和高都放大了2倍 transform:scale(2）：只写一个参数，第二个参数则和第一个参数一样，相当于scale(2,2) transform:scale(0.5,0.5) : 缩小sacle缩放最大的优势：可以设置转换中心点缩放，默认以中心点缩放的，而且不影响其他盒子</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>transform:scale(x,y);</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><h2 id="综合写法" tabindex="-1"><a class="header-anchor" href="#综合写法"><span>综合写法</span></a></h2><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>transform: translate（50px, 50px) rotate(180deg);</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>其顺序会影转换的效果。（先旋转会改变坐标轴向） <mark>当我们同时有位移和其他属性的时候，记得要将位移放到最前面</mark></p><h1 id="动画" tabindex="-1"><a class="header-anchor" href="#动画"><span>动画</span></a></h1><p>可通过设置多个节点来精确控制一个或一组动画，常用来实现复杂的动画效果。 相比较过渡，动画可以实现更多变化，更多控制，连续自动播放等效果。</p><div class="language- line-numbers-mode has-collapsed-lines collapsed" data-highlighter="shiki" data-ext="" style="--vp-collapsed-lines:15;--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>//定义动画</span></span>
<span class="line"><span>        @keyframes 动画名称 {</span></span>
<span class="line"><span>            0% {</span></span>
<span class="line"><span>                效果</span></span>
<span class="line"><span>            }</span></span>
<span class="line"><span></span></span>
<span class="line"><span>            100% {</span></span>
<span class="line"><span>                效果</span></span>
<span class="line"><span>            }</span></span>
<span class="line"><span>        }</span></span>
<span class="line"><span></span></span>
<span class="line"><span>//调用动画</span></span>
<span class="line"><span>div{</span></span>
<span class="line"><span>	animation-name:动画名称;</span></span>
<span class="line"><span>	//持续时间</span></span>
<span class="line"><span>	animation-duration:持续时间;</span></span>
<span class="line"><span>}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div><div class="collapsed-lines"></div></div><p><strong>动画序列</strong> 0%是动画的开始，100%是动画的完成。这样的规则就是动画序列。 关键词from&quot;和&quot;to”，等同于0%和100%。 可以分割动画序列设定多个状态</p><table><thead><tr><th>属性</th><th>描述</th></tr></thead><tbody><tr><td>@keyframes</td><td>规定动画。</td></tr><tr><td>animation</td><td>所有动画属性的简写属性，除了animation-play-state属性。</td></tr><tr><td>animation-name</td><td>规定@keyframes动画的名称。（必须的）</td></tr><tr><td>animation-duration</td><td>规定动画完成一个周期所花费的秒或毫秒，默认是0。（必须的）</td></tr><tr><td>animation-timing-function</td><td>规定动画的速度曲线，默认是&quot;ease&quot;</td></tr><tr><td>animation-delay</td><td>规定动画何时开始，默认是0。</td></tr><tr><td>animation-iteration-count</td><td>规定动画被播放的次数，默认是1，还有infinite</td></tr><tr><td>animation-direction</td><td>规定动画是否在下一周期逆向播放，默认是“normal“,alternate逆播放</td></tr><tr><td>animation-play-state</td><td>规定动画是否正在运行或暂停。默认是&quot;running&quot;还有&quot;pause&quot;。</td></tr><tr><td>animation-fill-mode</td><td>规定动画结束后状态，保持forwards回到起始backwards<br></td></tr></tbody></table><h2 id="动画属性简写" tabindex="-1"><a class="header-anchor" href="#动画属性简写"><span>动画属性简写</span></a></h2><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>animation：动画名称 持续时间 运动曲线 何时开始 播放次数 是否反方向 动画起始或者结束的状态;</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>简写属性里面不包含animation-play-state</p><h2 id="动画曲线" tabindex="-1"><a class="header-anchor" href="#动画曲线"><span>动画曲线</span></a></h2><p>animation-timing-function：规定动画的速度曲线，默认是&quot;ease&#39;</p><table><thead><tr><th>值</th><th>描述</th></tr></thead><tbody><tr><td>linear</td><td>动画从头到尾的速度是相同的。匀速</td></tr><tr><td>ease</td><td>默认。动画以低速开始，然后加快，在结束前变慢。</td></tr><tr><td>ease-in</td><td>动画以低速开始。</td></tr><tr><td>ease-out</td><td>动画以低速结束。</td></tr><tr><td>ease-in-out</td><td>动画以低速开始和结束。</td></tr><tr><td>steps()</td><td>指定了时间函数中的间隔数量（步长）</td></tr></tbody></table><h1 id="_3d转换" tabindex="-1"><a class="header-anchor" href="#_3d转换"><span>3D转换</span></a></h1><h2 id="translate3d" tabindex="-1"><a class="header-anchor" href="#translate3d"><span>translate3d</span></a></h2><p>3D移动在2D移动的基础上多加了一个可以移动的方向，就是z轴方向。</p><h2 id="透视perspective" tabindex="-1"><a class="header-anchor" href="#透视perspective"><span>透视perspective</span></a></h2><p>在2D平面产生近大远小视觉立体，但是只是效果二维的 如果想要在网页产生3D效果需要透视 设置视距,视距越大看到的图形越小,设置到盒子中</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>perspective:200px;</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><h2 id="_3d旋转rotate3d" tabindex="-1"><a class="header-anchor" href="#_3d旋转rotate3d"><span>3D旋转rotate3d</span></a></h2><p>3D旋转指可以让元素在三维平面内沿着x轴，y轴，z轴或者自定义轴进行旋转。</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>transform:rotate3d(x,y,z,deg)</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>沿着自定义轴旋转 deg为角度（了解即可)xyz是表示旋转轴的矢量，是标示你是否希望沿着该轴旋转，最后一个标示旋转的角度。</p><h2 id="_3d呈现transfrom-style" tabindex="-1"><a class="header-anchor" href="#_3d呈现transfrom-style"><span>3D呈现transfrom-style</span></a></h2><p>控制子元素是否开启三维立体环境。 transform-style:flat子元素不开启3d立体空间默认的 如果不开启3d空间,当子盒子3d变换后能看到变换的效果,如果再进行3d变换子盒子会丢失3d效果 transform-style:preserve-3d;子元素开启立体空间 代码写给父级，但是影响的是子盒子</p>`,89)]))}const p=a(t,[["render",d]]),h=JSON.parse('{"path":"/front/css/9/","title":"9 CSS3","lang":"zh-CN","frontmatter":{"title":"9 CSS3","createTime":"2025/06/18 21:06:16","permalink":"/front/css/9/"},"readingTime":{"minutes":8.85,"words":2654},"git":{"createdTime":1750599657000,"updatedTime":1750599657000,"contributors":[{"name":"pink","username":"pink","email":"pinkdopeybug@163.com","commits":1,"avatar":"https://avatars.githubusercontent.com/pink?v=4","url":"https://github.com/pink"}]},"filePathRelative":"notes/前端/CSS/9 CSS3.md","headers":[]}');export{p as comp,h as data};
